class Solution {
    public int getMinSwaps(String num, int k) {
        char[] nums = num.toCharArray();
        Arrays.sort(nums);
        String base = new String(nums);
        String target = getKthString(num, k);
        return getSwapSteps(num, target);
    }

    private String getKthString(String num, int k) {
        char[] count = new char[10];
        for (char c : num.toCharArray()) {
            count[c - '0']++;
        }
        StringBuilder sb = new StringBuilder();
        k--;
        for (int i = 0; i < num.length(); i++) {
            for (int j = 0; j < 10; j++) {
                if (count[j] > 0) {
                    if (k >= factorial(count, j)) {
                        k -= factorial(count, j);
                        count[j]--;
                    } else {
                        sb.append(j);
                        count[j]--;
                        break;
                    }
                }
            }
        }
        return sb.toString();
    }

    private int factorial(char[] count, int skip) {
        int res = 1;
        int sum = 0;
        for (int i = 0; i < 10; i++) {
            if (i != skip) {
                sum += count[i];
                res *= sum;
            }
        }
        return res;
    }

    private int getSwapSteps(String source, String target) {
        char[] s = source.toCharArray();
        char[] t = target.toCharArray();
        int steps = 0;
        for (int i = 0; i < s.length; i++) {
            if (s[i] != t[i]) {
                int j = i + 1;
                while (s[j] != t[i]) j++;
                while (j > i) {
                    char temp = s[j];
                    s[j] = s[j - 1];
                    s[j - 1] = temp;
                    steps++;
                    j--;
                }
            }
        }
        return steps;
    }
}
